import{_ as a,o as i,c as e,ag as l}from"./chunks/framework.DXGyWiRo.js";const d="/assets/image-20260305113536697.Dd_fJu-O.png",r="/assets/image-20260305203855896.JOM1JnKo.png",p="/assets/image-20260305204755413.DYuM0UPY.png",s="/assets/image-20260305204823012.CEs1U--S.png",T="/assets/image-20260305122519594.Bobd-Gmi.png",o="/assets/image-20260306170906562.BFPgRc5W.png",u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ES/Stm32/Stm32外设/TIM.md","filePath":"ES/Stm32/Stm32外设/TIM.md","lastUpdated":1775898880000}'),n={name:"ES/Stm32/Stm32外设/TIM.md"};function I(m,t,_,h,M,c){return i(),e("div",null,[...t[0]||(t[0]=[l('<h3 id="tim简介" tabindex="-1">TIM简介 <a class="header-anchor" href="#tim简介" aria-label="Permalink to &quot;TIM简介&quot;">​</a></h3><p>本文以 STM32F1 系列单片机为例介绍定时器模块。STM32F1 系列单片机的定时器模块被分为以下三类：</p><table tabindex="0"><thead><tr><th>定时器类型</th><th>定时器</th><th>计数器位数</th><th>计数模式</th><th>捕获/比较通道</th><th>互 补输出</th><th>应用场景</th></tr></thead><tbody><tr><td>基本定时器</td><td>TIM6，TIM7</td><td>16</td><td>递增</td><td>0</td><td>无</td><td>基础定时</td></tr><tr><td>通用定时器</td><td>TIM2，TIM3，TIM4，TIM5</td><td>16</td><td>递 增 、 递减、中央对齐</td><td>4</td><td>无</td><td>测量信号脉宽、产生PWM、定时计数等。</td></tr><tr><td>高级定时器</td><td>TIM1，TIM8</td><td>16</td><td>递 增 、 递减、中央对齐</td><td>4</td><td>有</td><td>电机控制、数字电源变换等。</td></tr></tbody></table><h3 id="tim结构" tabindex="-1">TIM结构 <a class="header-anchor" href="#tim结构" aria-label="Permalink to &quot;TIM结构&quot;">​</a></h3><p>STM32F1 系列单片机高级定时器结构如下，大体上分为时钟信号输入部分、时基单元、输入捕获和输出比较部分：</p><p><img src="'+d+'" alt="image-20260305113536697"></p><p>名词解释：</p><ul><li>TRGI：Trigger Input（触发输入）</li><li>TI1FP：Timer Input 1Filtered Polarity（仅上升或下降沿计数）</li><li>TI1F_ED：Timer Input 1Filtered Edge Detection（边沿检测，两个边缘均计数）</li><li>IC：Input Capture（输入捕获）</li><li>OC：Output Compare（输出比较）</li></ul><h4 id="时基单元" tabindex="-1">时基单元 <a class="header-anchor" href="#时基单元" aria-label="Permalink to &quot;时基单元&quot;">​</a></h4><p>时钟源有以下选择：</p><ul><li>内部时钟(CK_INT)：APB 总线时钟经过定时器内部倍频/分频后的时钟。</li><li>外部时钟模式1：用通道（TI1 和 TI2）引脚上信号的边沿做时钟，计数外部脉冲。</li><li>外部时钟模式2：使用专用的 ETR 引脚作为定时器时钟。</li><li>内部触发输入(ITRx)：每根线连接某个定时器的 TRGO，使用一个定时器作为另一个定时器的预分频器。</li></ul><p>时基单元通过对时钟信号进行计数来实现计时，包含以下部分：</p><ul><li>计数器寄存器(TIMx_CNT)：存放计数值。</li><li>预分频器寄存器 (TIMx_PSC)：设置对时钟源进行的几分频。</li><li>自动装载寄存器 (TIMx_ARR)：向上计数时计数到ARR的大小后归零。</li><li>重复次数寄存器 (TIMx_RCR)：用于设置溢出几次才会发生更新事件。</li></ul><h4 id="输入捕获-输出比较" tabindex="-1">输入捕获/输出比较 <a class="header-anchor" href="#输入捕获-输出比较" aria-label="Permalink to &quot;输入捕获/输出比较&quot;">​</a></h4><p>TI1-TI4 这四个通道用于实现定时器的输入捕获/输出比较功能。</p><ul><li>输入捕获：通过分别记录 TI 通道上输入信号上升沿与下降沿来临时 CNT 值从而测量输入信号持续的时间。</li><li>输出比较：通过对比 CNT 值与捕获/比较寄存器的值来决定输出信号的电平。</li></ul><p>下图是捕获/比较的主电路，当发生<code>capture_transfer</code>和<code>compare_transfer</code>时预装载寄存器与影子寄存器会发生数据更新（传递方向由箭头所示），发生条件是相连接的与门输出为真。在输入捕获模式下，当满足输入捕获的条件时会将计数器中的值自动锁入影子寄存器，未使用预装载寄存器（OCxPE=’0’）软件写入 CCRx 就更新，OCxPE=’1’ CCRX的影子寄存器只能在发生下一次更新事件时被更新；而输出比较模式下，比较器会一直比较计数器与影子寄存器的值满足条件后就会输出信号到输出模式控制器。</p><p><img src="'+r+'" alt="image-20260305203855896"></p><p>输入捕获通道（通道1）如下图所示，外部信号从 TI1 输入经过滤波器输入到边沿检测器中，输出信号的上边沿和下边沿，再经过选择器从 TI1 和 TI2 的上升沿和下降沿信号中选择一个作为 IC1 信号，最后通过分频器得到输入捕获信号。</p><p><img src="'+p+'" alt="image-20260305204755413"></p><p>输出比较通道（通道1至3）如下图所示，捕获/比较的主电路中比较器输出的信号会输入到输出模式控制器当中，进而输出OC1REF（输出比较参考信号）。OC1REF信号可以选择直接作为输出信号或者进入死区发生器，最终通道会输出OC1和OC1N（N = Negative），这个两个信号作为互补输出通常设置为相反极性，用以驱动半桥/全桥电路。驱动半桥/全桥时由于MOS管关闭需要时间，上管刚关、下管就立刻开有可能上下管同时导通导致烧管，因此需要死区发生器在两个信号间插入死区时间保证上下管不会同时打开。</p><p><img src="'+s+'" alt="image-20260305204823012"></p><h4 id="更新事件" tabindex="-1">更新事件 <a class="header-anchor" href="#更新事件" aria-label="Permalink to &quot;更新事件&quot;">​</a></h4><p>更新事件（UEV）发生时，定时器中<strong>带有缓冲/影子</strong>的寄存器的值会真正更新生效（例如：预装载寄存器的值会在更新事件发生时写入自动装载影子寄存器，从而真正更新重装载值），同时会将更新中断标志位置位（UIF）并产生更新中断/更新DMA请求。以下两种情况会发生更新事件：</p><ul><li>硬件自动产生：每次计数器溢出时会产生更新事件。如果使用了重复计数器功能，在计数次数达到设置的重复计数次数时，产生更新事件。</li><li>软件手动产生：在 TIMx_EGR 寄存器中置UG位也可以产生一个更新事件。</li></ul><p>下图是更新事件发生时，预分频器的缓冲区被置入预装载寄存器的值的时序图：</p><p><img src="'+T+'" alt="image-20260305122519594"></p><h3 id="主要模式" tabindex="-1">主要模式 <a class="header-anchor" href="#主要模式" aria-label="Permalink to &quot;主要模式&quot;">​</a></h3><p>PWM 输入模式：使用两路通道测量PWM信号的周期和占空比，一路通道用上升沿捕获+复位计数得周期，另一路用下降沿捕获得高电平宽度，两次捕获共享同一个计数器。</p><p>PWM输出模式：相较于一般 OC 只在比较点执行动作，PWM模式由TIMx_ARR寄存器确定频率、由TIMx_CCRx寄存器确定占空比，在 CNT &lt; ARR 时通道输出一种电平，在 CNT &gt; ARR 时输出另一种电平从而产生 PWM，还有中心对称模式用于输出每个周期波形都中心对称的 PWM。</p><ul><li>PWM模式1－ 在向上计数时，一旦TIMx_CNT&lt;TIMx_CCR1时通道1为有效电平，否则为无效电平；在向下计数时，一旦TIMx_CNT&gt;TIMx_CCR1时通道1为无效电平(OC1REF=0)，否则为有效电平(OC1REF=1)。</li><li>PWM模式2－ 在向上计数时，一旦TIMx_CNT&lt;TIMx_CCR1时通道1为无效电平，否则为有效电平；在向下计数时，一旦TIMx_CNT&gt;TIMx_CCR1时通道1为有效电平，否则为无效电平</li></ul><p>编码器接口模式：两个输入TI1和TI2被用来作为增量编码器的接口。</p><p><img src="'+o+'" alt="image-20260306170906562"></p><p>强置输出模式：定时器正常运行，通道输出有效电平或无效电平由软件设定。</p><p>单脉冲输出模式：定时器只运行一个周期，输出单个脉冲就停止。</p>',35)])])}const g=a(n,[["render",I]]);export{u as __pageData,g as default};
